changeSet.sql:
INSERT INTO cargo_body_types (cargo_id, body_type_code) SELECT cargo.id, COALESCE(dictionary.code, item.value) FROM cargo CROSS JOIN LATERAL jsonb_array_elements_text(COALESCE(cargo.body_types, '[]'::jsonb)) AS item(value) LEFT JOIN body_type_dictionary dictionary ON dictionary.code = item.value OR lower(dictionary.label) = lower(item.value) WHERE item.value IS NOT NULL AND item.value <> '';
INSERT INTO cargo_loading_types (cargo_id, loading_type_code) SELECT cargo.id, COALESCE(dictionary.code, item.value) FROM cargo CROSS JOIN LATERAL jsonb_array_elements_text(COALESCE(cargo.loading_types, '[]'::jsonb)) AS item(value) LEFT JOIN loading_type_dictionary dictionary ON dictionary.code = item.value OR lower(dictionary.label) = lower(item.value) WHERE item.value IS NOT NULL AND item.value <> '';
INSERT INTO cargo_unloading_types (cargo_id, loading_type_code) SELECT cargo.id, COALESCE(dictionary.code, item.value) FROM cargo CROSS JOIN LATERAL jsonb_array_elements_text(COALESCE(cargo.unloading_types, '[]'::jsonb)) AS item(value) LEFT JOIN loading_type_dictionary dictionary ON dictionary.code = item.value OR lower(dictionary.label) = lower(item.value) WHERE item.value IS NOT NULL AND item.value <> '';
